CREATE TABLE IF NOT EXISTS legacy_voyage_history (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  source_row INTEGER,
  record_date TEXT NOT NULL,
  etd_time TEXT,
  voyage_id INTEGER NOT NULL,
  skipper_username TEXT,
  arrival_port TEXT,
  status TEXT NOT NULL CHECK (status IN ('COMPLETED','CANCELLED')),
  revenue_florins INTEGER,
  profit_florins INTEGER,
  loss_florins INTEGER,
  crew_usernames TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS legacy_voyage_salaries (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  source_row INTEGER,
  record_date TEXT NOT NULL,
  voyage_id INTEGER NOT NULL,
  recipient_username TEXT NOT NULL,
  revenue_florins INTEGER,
  salary_florins INTEGER,
  catch_summary TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS legacy_finance_entries (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  source_row INTEGER,
  record_date TEXT NOT NULL,
  voyage_id INTEGER,
  entry_type TEXT NOT NULL,
  from_username TEXT,
  to_username TEXT,
  amount_florins INTEGER,
  notes TEXT,
  solved_by_username TEXT,
  status TEXT NOT NULL CHECK (status IN ('SOLVED','UNSOLVED')),
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_legacy_history_voyage_id ON legacy_voyage_history(voyage_id);
